INSERT INTO `exams` VALUES (1,'C Programming Evaluation Exam','This exam is intended to assess knowledge of procedural programming using C. It includes hands-on problems involving pointers, recursion, and memory access. Questions range from basic syntax to memory layout and file operations in C.','2025-06-20','2025-07-15',20,1,'ONGOING','2025-06-17 00:31:44',20,3),(2,'Python Fundamentals Exam','This exam evaluates your understanding of core Python syntax and problem-solving using Python. It includes MCQs, coding snippets, and case-based questions on real-world Python applications. Topics include OOP, functions, file handling, and control flow.','2025-06-18','2025-07-15',20,2,'ONGOING','2025-06-18 01:42:48',20,3),(3,'Java Core Concepts Exam','This exam assesses the proficiency in Java programming fundamentals, including exception handling, OOP principles, and usage of collection APIs. It includes scenario-based coding questions and conceptual MCQs.','2025-07-01','2025-07-31',20,3,'ONGOING','2025-07-01 05:55:04',20,3),(4,'Devops','The DevOps Examination is structured to test your practical understanding of tools, workflows, and real-world implementation scenarios in modern DevOps environments.','2025-07-09','2025-07-26',20,4,'ONGOING','2025-07-09 07:40:18',20,3),(5,'c language','C language exam which covers basics to advance topics','2025-07-14','2025-07-31',20,1,'ONGOING','2025-07-14 01:30:22',20,3);
