--
-- Table structure for table `questions`
--

DROP TABLE IF EXISTS `questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `questions` (
  `question_id` int NOT NULL AUTO_INCREMENT,
  `exam_id` int DEFAULT NULL,
  `question_text` text NOT NULL,
  `question_type` enum('MCQ','MSQ','TrueFalse','CodingSnippet') NOT NULL,
  `marks` int DEFAULT '1',
  `subtopic_id` int DEFAULT NULL,
  `difficulty_level` enum('Basic','Intermediate','Advance') NOT NULL DEFAULT 'Intermediate',
  PRIMARY KEY (`question_id`),
  KEY `exam_id` (`exam_id`),
  KEY `subtopic_id` (`subtopic_id`),
  CONSTRAINT `questions_ibfk_1` FOREIGN KEY (`exam_id`) REFERENCES `exams` (`exam_id`) ON DELETE CASCADE,
  CONSTRAINT `questions_ibfk_2` FOREIGN KEY (`subtopic_id`) REFERENCES `subtopics` (`subtopic_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=251 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

