INSERT INTO `subjects` VALUES (1,'C Programming','C is a foundational, procedural programming language widely used for system-level programming, embedded systems, and OS development. It emphasizes performance and memory control.','2025-06-17 00:29:13',2,'ACTIVE'),(2,'Python Programming','Python is a high-level, versatile programming language known for its readability and vast library support. It is widely used for web development, data science, automation, AI/ML, and scripting.','2025-06-18 01:40:07',2,'ACTIVE'),(3,'Java Programming','Java is an object-oriented, class-based programming language designed for portability and performance. It is heavily used in enterprise software, Android development, and backend systems.Java is an object-oriented, class-based programming language designed for portability and performance. It is heavily used in enterprise software, Android development, and backend systems.','2025-06-27 05:44:59',2,'ACTIVE'),(4,'Devops Fundamentals','DevOps is a set of practices that combines software development (Dev) and IT operations (Ops).This subject covers foundational tools, principles, and automation techniques that enable continuous integration, delivery, and deployment.','2025-07-09 07:36:43',2,'ACTIVE'),(5,'Aptitude','This exam covers all the topics of Quantitative Aptitude, Logical Reasoning, and Verbal Ability.','2025-07-12 03:25:02',2,'ACTIVE'),(6,'Web Development','This subject covers the core principles and practical applications involved in building websites and web applications using modern front-end and back-end technologies.','2025-07-14 00:46:34',2,'ACTIVE');
